@_documentation(visibility: private)
#endif
public func FfiConverterTypeMyceliumClient_lower(_ value: MyceliumClient) -> UnsafeMutableRawPointer {
    return FfiConverterTypeMyceliumClient.lower(value)
}


/**
 * This device's own account, for the profile/settings screen.
 */
public struct Account {
    /**
     * The registered handle (empty until `register`).
     */
    public var handle: String
    /**
     * The chosen display name (empty until `register`).
     */
    public var name: String
    /**
     * The account's wallet public key, lowercase hex — a stable account id.
     */
    public var walletAddress: String

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * The registered handle (empty until `register`).
         */handle: String, 
        /**
         * The chosen display name (empty until `register`).
         */name: String, 
        /**
         * The account's wallet public key, lowercase hex — a stable account id.
         */walletAddress: String) {
        self.handle = handle
        self.name = name
        self.walletAddress = walletAddress
    }
}



extension Account: Equatable, Hashable {
    public static func ==(lhs: Account, rhs: Account) -> Bool {
        if lhs.handle != rhs.handle {
            return false
        }
        if lhs.name != rhs.name {
            return false
        }
        if lhs.walletAddress != rhs.walletAddress {
            return false
        }
        return true
    }

