/**
 * Every error that can cross the boundary. Internal `anyhow`/engine errors are
 * mapped into one of these variants; the underlying error is never leaked.
 */
public enum SdkError {

    
    
    /**
     * An operation needing a published record was called before `register`.
     */
    case NotRegistered
    /**
     * A network/transport/server failure talking to the directory or queue.
     */
    case Network(
        /**
         * A human-readable description (no secrets).
         */msg: String
    )
    /**
     * A local storage (filesystem/serialization) failure.
     */
    case Storage(
        /**
         * A human-readable description (no secrets).
         */msg: String
    )
    /**
     * A cryptographic failure (sealing/opening/identity).
     */
    case Crypto(
        /**
         * A human-readable description (no secrets).
         */msg: String
    )
    /**
     * A caller-supplied argument was invalid (e.g. a malformed handle).
     */
    case InvalidInput(
        /**
         * A human-readable description.
         */msg: String
    )
    /**
     * A peer's wallet no longer matches what we pinned/verified — treat as a
     * possible impersonation and re-verify out of band.
     */
    case IdentityChanged(
        /**
         * The affected peer handle.
         */handle: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeSdkError: FfiConverterRustBuffer {
    typealias SwiftType = SdkError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SdkError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .NotRegistered
        case 2: return .Network(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 3: return .Storage(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 4: return .Crypto(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 5: return .InvalidInput(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 6: return .IdentityChanged(
            handle: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: SdkError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case .NotRegistered:
            writeInt(&buf, Int32(1))
        
        
        case let .Network(msg):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(msg, into: &buf)
            
        
        case let .Storage(msg):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(msg, into: &buf)
            
        
        case let .Crypto(msg):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(msg, into: &buf)
            
        
        case let .InvalidInput(msg):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(msg, into: &buf)
            
        
        case let .IdentityChanged(handle):
            writeInt(&buf, Int32(6))
            FfiConverterString.write(handle, into: &buf)
            
        }
    }
}


