// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * How much we trust that a peer's current wallet is really theirs. Mirrors
 * [`mycellium_engine::verified::TrustLevel`].
 */

public enum TrustLevel {
    
    /**
     * Never pinned or verified — a first, unverified contact.
     */
    case unverified
    /**
     * Pinned on first use (TOFU), but not out-of-band verified.
     */
    case pinned
    /**
     * Confirmed out of band — the safety number matched.
     */
    case verified
    /**
     * A wallet was pinned/verified before but the current one differs.
     */
    case changed
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeTrustLevel: FfiConverterRustBuffer {
    typealias SwiftType = TrustLevel

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> TrustLevel {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .unverified
        
        case 2: return .pinned
        
        case 3: return .verified
        
        case 4: return .changed
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: TrustLevel, into buf: inout [UInt8]) {
        switch value {
        
        
        case .unverified:
            writeInt(&buf, Int32(1))
        
        
        case .pinned:
            writeInt(&buf, Int32(2))
        
        
        case .verified:
